import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NUMBERS = {
    "14": {
        "1": "<p>The congregation's response to the spies' report: communal weeping through the night (<em>wayyiśśəʾû qôlām wayyibkû</em>). The verb <strong>נָשָׂא קוֹל (nāśāʾ qôl)</strong> — to lift up the voice — indicates uninhibited public lamentation. The text presents a community in crisis, making a fundamentally theological error: treating the honest assessment of military difficulty as grounds for abandoning the covenant promise.</p>",
        "2": "<p><strong>לוּן (lûn)</strong> — to murmur/grumble — is the characteristic sin-verb of the wilderness generation (Exod 15:24; 16:2; 17:3; Num 14:2,29; 17:6). The verb implies persistent, complaining discontent against authority. The complaint is directed against Moses and Aaron but represents a rejection of YHWH himself (v11). The counter-factual wish (<em>lû-metnû</em> — if only we had died) anticipates YHWH's ironic sentence in v29.</p>",
        "3": "<p>The congregation's theology of providence has inverted: YHWH is bringing them to the land not to give it to them but <em>to fall by the sword</em>. The protective concern cited — wives and children becoming prey — is then turned against them in v31, where YHWH says precisely those children will inherit what the adults refused. The question <em>halôʾ ṭôb lānû šûḇ miṣrāymâ</em> — would it not be better for us to return to Egypt — forms the climactic rejection of exodus-redemption.</p>",
        "4": "<p>The appointment of a new leader to lead a return to Egypt (<em>nittənâ rōʾš wənāšûḇâ miṣrāymâ</em>) would mean the undoing of the exodus — electing back into slavery. The irony throughout the wilderness narratives is that the people consistently idealize Egypt (Num 11:5; 20:5) while forgetting its conditions of oppression. The verb <strong>נָתַן רֹאשׁ (nātan rōʾš)</strong> — to appoint a head/leader — echoes the language of Deut 17:14-15, the future kingship law, suggesting the people want an alternative national structure built on human initiative rather than divine leading.</p>",
        "5": "<p>Moses and Aaron <strong>נָפַל עַל-פְּנֵיהֶם (nāp̱al ʿal-pənêhem)</strong> — fell on their faces — before the assembly. This is the intercession/petition posture, appearing also in Num 16:4,22,45; 17:10; 20:6. It enacts their identification with the people before YHWH and signals desperate appeal rather than passive submission. The same act appears in ch16 when Moses intercedes for Korah's rebellion, showing it is his consistent response to communal crisis.</p>",
        "6": "<p>Joshua and Caleb tear their clothes (<em>qārəʿû bigdêhem</em>) — the mourning rite expressing grief, often in response to blasphemy or catastrophe (Gen 37:29; 2 Sam 1:11; Matt 26:65). Here it expresses anguish at the congregation's faithlessness. Caleb is identified as the son of Jephunneh; Joshua as the son of Nun; both are named explorers from ch13, witnesses to the land, whose minority report is being rejected.</p>",
        "7": "<p>The explorers' counterassessment uses <strong>טוֹב מְאֹד מְאֹד (ṭôḇ məʾōḏ məʾōḏ)</strong> — exceedingly, exceedingly good — the doubled intensifier signaling enthusiastic affirmation beyond ordinary superlative. They have seen what the fearful majority saw; they interpret it differently. The theological category at stake is not military intelligence but trust in the divine promise attached to the land.</p>",
        "8": "<p><em>ʾim-ḥāp̱ēṣ bānû YHWH</em> — if YHWH is pleased with us — literally if YHWH delights in us, using the verb <strong>חָפֵץ (ḥāp̱ēṣ)</strong> which expresses deep desire or delight. The conditional is not doubt about YHWH's intent but an acknowledgment that the covenant relationship is the precondition for conquest. The formula <em>ʾereṣ zāḇat ḥālāḇ ûḏeḇaš</em> — land flowing with milk and honey — occurs here in the mouths of the minority-report spies affirming what the congregation has just rejected.</p>",
        "9": "<p><em>leḥem hēm lānû</em> — they are bread for us — uses <strong>לֶחֶם (leḥem)</strong>, food/bread, as a metaphor for the enemies of Canaan: the Israelites will consume them the way one eats a meal. The enemies' <em>ṣillām</em> — their shade/protection — has departed; the idiom suggests divine covering has withdrawn, leaving them vulnerable. <strong>אַל-תִּירָאוּ (ʾal-tîrəʾû)</strong> — do not fear — is the covenant formula addressing the fundamental problem: the congregation's failure is not military analysis but fear replacing faith.</p>",
        "10": "<p>The congregation responds to Caleb and Joshua with the demand to stone them (<em>ligmôr ʾōtām bāʾăḇānîm</em>) — the standard penalty for blasphemy and for incitement to apostasy (Deut 13:10; 17:5). At this moment, the <strong>כְּבוֹד יְהוָה (kəḇôḏ YHWH)</strong> — the glory of YHWH — appears at the tent of meeting, as in the crises of Num 16:19 and 17:7. The divine glory appearance interrupts the proceedings with theophanic authority.</p>",
        "11": "<p>YHWH's opening question to Moses: <em>ʿad-ānâ yənabbezûnî hāʿām hazzeh</em> — how long will this people despise me? The verb <strong>נָאַץ (nāʾaṣ)</strong> — to spurn/despise — is a strong term for treating someone of high status with contempt (Ps 10:3; 74:18; Isa 1:4). The failure to believe despite signs (<em>ʾôtôt</em>) frames the sin as cognitive rather than purely moral: they have seen the evidence and rejected it. Ten times (<em>ʿeśer pəʿāmîm</em>) — an idiom for repeated, patterned transgression rather than a precise count.</p>",
        "12": "<p>YHWH's threat to disinherit Israel and make Moses a new and greater nation echoes the golden calf episode (Exod 32:10). The offer to rebuild from Moses forms a test of Moses's intercession — and Moses refuses it (v13), as he refused it at Sinai. The pattern establishes Moses as paradigmatic intercessor who consistently chooses communal redemption over personal greatness.</p>",
        "13": "<p>Moses's intercession argument begins with <em>reputational logic</em>: Egypt has already heard (<em>šāməʿû miṣrāyim</em>) about YHWH's power among this people. The verb <strong>שָׁמַע (šāmaʿ)</strong> — to hear — frames the nations as witnesses to the covenant relationship. Divine judgment on Israel would not go uninterpreted; the nations would draw theological conclusions about YHWH's ability or willingness to fulfill his promises.</p>",
        "14": "<p>The broader ANE world has heard: YHWH is among this people (<em>bəqereḇ hāʿām hazzeh</em>), appearing face to face (<em>ʿayin bəʿayin</em>) — the most intimate possible presence idiom. The pillar of cloud by day and pillar of fire by night (<em>ʿamûḏ ʿānān</em>) are the visible signs of divine accompaniment. Moses's intercession catalogues exactly what has been witnessed, making YHWH's reputation among the nations the stake of his decision.</p>",
        "15": "<p><em>wehēmattâ ʾet-hāʿām hazzeh kəʾîš ʾeḥāḏ</em> — if you kill this people as one man — the phrase emphasizes collective totality rather than individual death. Moses's concern is that mass destruction of Israel would be read not as divine justice but as divine inability to bring about the promised conquest. The nations who have heard YHWH's fame (<em>šimʿăkā</em>) would form wrong theological conclusions.</p>",
        "16": "<p>The anticipated pagan interpretation: <em>mibbiltî yəkōlet YHWH</em> — because YHWH was not able (<em>yākōl</em>, capable/powerful). Divine abandonment of Israel would be indistinguishable, from the nations' viewpoint, from divine impotence. The argument turns on the connection between YHWH's reputation among the nations and his treatment of Israel — a connection that pervades Moses's intercessions and the prophets' theology of exile and restoration.</p>",
        "17": "<p>Moses appeals directly: <em>wəʿattâ yigdal-nāʾ kōaḥ ʾăḏōnāy</em> — and now, let the power of my Lord be great. The verb <strong>גָּדַל (gāḏal)</strong> in the jussive = may it be great/may it prove itself great. Moses is not doubting YHWH's power but asking for its expression in mercy rather than judgment — a display of power to forgive that exceeds the power to destroy. The formula <em>kaʾăšer dibbartā</em> — as you have spoken — grounds the appeal in YHWH's own prior disclosure.</p>",
        "18": "<p>Moses quotes the Thirteen Attributes proclaimed at Sinai after the golden calf (Exod 34:6-7): <em>ʾerek ʾappayim wərabb-ḥeseḏ nōśēʾ ʿāwōn wāp̱āšaʿ wənaqēh lōʾ yənaqeh</em> — slow to anger, abounding in steadfast love, forgiving iniquity and transgression, but by no means clearing the guilty. <strong>אֶרֶךְ אַפַּיִם (ʾerek ʾappayim)</strong> — long-nosed, i.e., slow to flare with anger; <strong>חֶסֶד (ḥeseḏ)</strong> — covenant loyalty/lovingkindness; <strong>נָשָׂא עָוֹן (nāśāʾ ʿāwōn)</strong> — to bear/lift/carry iniquity, the forgiveness metaphor. Moses uses YHWH's own self-description as the basis of the appeal.</p>",
        "19": "<p><em>selaḥ-nāʾ laʿăwōn hāʿām hazzeh</em> — please pardon the iniquity of this people. The verb <strong>סָלַח (sālaḥ)</strong> — to forgive, to pardon — appears only with YHWH as subject in the Hebrew Bible; it is exclusively divine forgiveness vocabulary (Exod 34:9; Lev 4:20; Num 15:25-28; 1 Kgs 8:30). <em>kəgōḏel ḥasdekā</em> — according to the greatness of your steadfast love — appeals to the character revealed in v18 as the metric of forgiveness. The model cited: you have forgiven this people from Egypt until now.</p>",
        "20": "<p><em>sālahti kidəḇārekā</em> — I have pardoned according to your word. The divine pardon is immediate and total. The phrase <em>kidəḇārekā</em> — according to your word — is remarkable: YHWH's forgiveness is shaped by Moses's intercession. This does not mean Moses commands God but that God has chosen to be responsive to faithful prayer — a pattern that appears throughout the psalms and prophets. The pardon is real, but it does not cancel the consequences stated in vv21-35.</p>",
        "21": "<p><em>ûlûlām ḥay-ʾănî</em> — but as I live — the divine oath formula introducing absolute certainty. What follows cannot be revoked: <em>weyimmālēʾ kəḇôḏ-YHWH ʾet-kol-hāʾāreṣ</em> — all the earth shall be filled with the glory of YHWH. The universal glory-filling is asserted as the larger telos within which Israel's particular failure is a subplot. The forgiveness of v20 and the sentence of v22-35 exist within YHWH's larger purpose of world-filling glory.</p>",
        "22": "<p>The participle <em>hāʾănāšîm hārōʾîm ʾet-kəḇôḏî</em> — the men who have seen my glory — identifies the condemned generation precisely by what they witnessed. Seeing the signs in Egypt and the wilderness (ten times, v11) and still failing to trust defines the wilderness generation's sin: exposure to maximum revelation combined with persistent unbelief. The verb <strong>בָּחַן (bāḥan)</strong> — to test/try (v22) — is used both for testing metals and for testing divine loyalty (Ps 95:9).</p>",
        "23": "<p>The sentence: none of those who despised YHWH (<em>mənaʾăṣay</em>) shall see the promised land. The verb from v11 (<em>nāʾaṣ</em>) reappears — the specific charge of despising/spurning YHWH is the ground of the sentence. The Promised Land is withheld not as arbitrary punishment but as the natural consequence of refusing to enter it: those who said they could not take the land will not.</p>",
        "24": "<p>Caleb is the exception: <em>ʿeqeḇ hāyətâ rûaḥ ʾaḥeret ʿimmô</em> — because there was a different spirit with him. <strong>רוּחַ (rûaḥ)</strong> — spirit/wind/breath — here describes the animating disposition, something qualitatively distinct (<em>ʾaḥeret</em>) from the congregation's collective spirit of fear and grumbling. The phrase <em>waymallēʾ ʾaḥăray</em> — he has followed me fully (lit. filled after me) — uses <strong>מָלֵא (māleʾ)</strong>, the fullness verb, to describe complete devotion. This phrase becomes a technical descriptor for Caleb throughout (Num 32:12; Deut 1:36; Josh 14:8,9,14).</p>",
        "25": "<p>Tactical direction: since the Amalekites and Canaanites currently occupy the valleys (the military force that defeated the Israelites in Exod 17 is still present), YHWH redirects Israel toward the wilderness by the Sea of Reeds. The direction <em>ûsəʾû hammiḏbār</em> — set out for the wilderness — is both geographical and symbolic: the refusal to advance means retreat into the wilderness that represents their faithlessness.</p>",
        "26": "<p>A new divine speech unit (v26-38) elaborates the sentence with precise demographic detail. The repetition of the rebellious congregation's words in vv27-29 — YHWH directly quoting what they said — structures the punishment as an ironic fulfillment: they will get exactly what they asked for (death in the wilderness, v2). YHWH's justice here mirrors the form of the sin.</p>",
        "27": "<p><em>ʿaḏat hārāʿ hazzōʾt</em> — this wicked congregation. <strong>עֵדָה (ʿēḏâ)</strong> — congregation/assembly — is the formal term for the covenant community in covenant contexts; pairing it with <em>rāʿ</em> (wicked/evil) is strikingly condemnatory. The term <em>lûnnim</em> — grumblers — from the verb <em>lûn</em> (v2) identifies the primary sin: sustained communal complaining against divine leadership as a pattern of faithlessness.</p>",
        "28": "<p><em>ḥay-ʾănî nəʾum-YHWH</em> — as I live, declares YHWH — the double divine oath formula intensifies the irrevocable character of what follows. <em>kimmîmaṣʾûnî ʿōśeh lākem</em> — I will do to you just as you have said in my hearing. The sentence is structured as the fulfillment of their own expressed wish (v2: if only we had died in the wilderness). Divine justice here takes the form of granting what was spoken in faithlessness.</p>",
        "29": "<p>The condemned: everyone in the census from twenty years old and upward — the military census of ch1 now becomes the census of the condemned generation. <strong>פְּגָרִים (pəgārîm)</strong> — corpses/carcasses — the blunt term for dead bodies emphasizes the ignominious end of those who had the privilege of being the Exodus generation.</p>",
        "30": "<p>The exception clause singles out Caleb (son of Jephunneh) and Joshua (son of Nun). The verse uses the oath formula <em>nāśāʾtî ʾet-yāḏî</em> — I raised my hand (swore) — which is the standard covenantal oath gesture. The land promise is reaffirmed specifically to these two while being suspended for the rest. The contrast between the oath to the fathers (v16, Exod 32:13) and the sentence on the sons shows the radical consequences of covenant faithlessness.</p>",
        "31": "<p>The ironic reversal: <em>wəṭappekhem ʾăšer ʾămartem lābaz yihyeh</em> — your children whom you said would become prey — those children will inherit the land. The parental generation's stated concern for the children (v3) becomes the vehicle for the children's future while the parents are excluded. The verb <em>yadəʿû</em> — they shall know — suggests experiential knowledge of what the parents refused to believe.</p>",
        "32": "<p>The starkness of the sentence for the exodus generation: <em>piigarêkem ʾattem yippelû bammiḏbār hazzeh</em> — your corpses, you yourselves, will fall in this wilderness. The pronoun <em>ʾattem</em> — you yourselves — emphasizes personal accountability. The wilderness, which they preferred to the promised land, becomes their permanent dwelling and burial ground.</p>",
        "33": "<p>The children will bear (<em>nāsəʾû</em>) the weight of the parents' faithlessness (<em>zənûtêkem</em>) — the word <strong>זְנוּת (zənût)</strong> is the noun form of <em>zānâ</em>, meaning harlotry/faithlessness, the metaphor used throughout for Israel's apostasy (Hosea, Ezekiel). Forty years corresponds to the forty days of spying (v34) — a year for each day. The forty-year desert period now carries both judicial and formative significance.</p>",
        "34": "<p><em>yôm laššānâ yôm laššānâ</em> — a year for each day, a year for each day — the repeated formula marks the proportional calculus of divine judgment. Forty days of spying → forty years of wandering. The correspondences in Numbers between days and years appears again in the Day of Atonement (Lev 16) and elsewhere. The phrase <em>wîḏaʿtem ʾet-tənûʾātî</em> — you shall bear my opposition — uses the noun <strong>תְּנוּאָה (tənûʾâ)</strong>, a word for God's hostility or displeasure, appearing only here and in Job 33:10.</p>",
        "35": "<p>The divine oath of finality: <em>ʾănî YHWH dibbartî</em> — I, YHWH, have spoken. The sentence is against the <em>ʿēḏâ hāqāhāl</em> — the congregation gathered together against me. The preposition ʿal here has adversarial sense — gathered in opposition, not merely gathered. The sentence includes all members of the rebellious assembly; the wicked congregation will be consumed (<em>yittammû</em>) in the wilderness.</p>",
        "36": "<p>The ten spies who brought the false report (<em>môṣîʾê dibbat hāʾāreṣ rāʿâ</em> — those who brought up an evil report about the land) receive immediate judgment. The verb <strong>הוֹצִיא דִּבָּה (hôṣîʾ dibbâ)</strong> — to spread a slanderous report — is used in Gen 37:2 for Joseph's report to his father and in Prov 10:18 for slander. The theological charge is not honest pessimism but spreading a false narrative that caused the congregation to grumble.</p>",
        "37": "<p>The ten die <em>bammageep̱â</em> — by the plague/blow — a term for divine judgment-death throughout the wilderness narratives (Exod 9:14; Num 17:11-15; 25:8). The immediacy of their death — before the congregation receives the longer sentence — establishes the principle that those who led the apostasy bear the primary guilt and consequent primary judgment.</p>",
        "38": "<p>Only Joshua and Caleb remain alive (<em>wayyiḥəyû</em>) — the verb's simplicity is deliberate. Against the background of mass death, surviving is a theological statement about the consequence of the different spirit (v24). Their survival into the conquest generation will complete the narrative arc of ch14.</p>",
        "39": "<p>Moses reports the divine words to the congregation. Their response — <strong>אָבַל (ʾāḇal)</strong>, deep mourning (<em>wayyitʾabbəlû mːʾōḏ</em>) — contrasts with the weeping of v1. The weeping of v1 was self-pitying complaint; this mourning is grief at the real consequences of their faithlessness. The text distinguishes emotional responses by their object: the first weeping was about the land; this mourning is about YHWH's judgment.</p>",
        "40": "<p>The presumptuous advance: rising early (<em>wayyaškîmû ḇabōqer</em> — an idiom for eager action) they go up to the hill country, claiming <em>hinnennû</em> — here we are — the same term used in visions and callings (Gen 22:1,11; Isa 6:8) but here expressing penitent readiness. Their announcement that they will go up and sin no more (<em>ḥāṭāʾnû</em>) uses the right verb — sin acknowledgment — but the action that follows reveals incomplete repentance: they still presume on YHWH's presence.</p>",
        "41": "<p><em>lāmmâ zeh ʿōḇərîm ʾet-pî YHWH</em> — why are you now transgressing the mouth of YHWH? <strong>עָבַר עַל-פִּי (ʿāḇar ʿal-pî)</strong> — to transgress against the mouth/command — is a fixed phrase for disobeying a direct divine order (Num 20:24; 27:14; Deut 1:43). Moses's assessment is that the advance is not obedience but a different form of the same problem: self-willed action rather than faith. Presumption and paralysis are symmetric failures.</p>",
        "42": "<p><em>kî ʾên YHWH bəqirbekhem</em> — for YHWH is not among you. Divine absence from the battle makes the advance not courageous but reckless. The presence of YHWH (the ark of the covenant, v44) among the army was the sine qua non of holy war. Proceeding without the ark — the visible symbol of divine presence — inverts the logic of the conquest entirely, turning faith into presumption.</p>",
        "43": "<p>The Amalekites and Canaanites are described as standing before them (<em>lip̱nêkem</em>) — the same prepositional phrase used for enemies in a position of tactical advantage. <em>nəp̱altem beḥāreḇ</em> — you will fall by the sword — echoes v3's fear that had been rejected by Caleb and Joshua. The very outcome the congregation feared is now guaranteed precisely because they have abandoned the faith that would have prevented it.</p>",
        "44": "<p><em>wayyaʿpilû laʿălôt</em> — they presumed to go up. The verb <strong>עָפַל (ʿāp̱al)</strong> appears only here and in Hab 2:4 (in the famous contrast between the puffed-up and the righteous who lives by faith). Arrogant presumption — the exact semantic value here — is the theological mirror of the faithlessness of vv1-4. The ark (<em>ʾărôn bərît YHWH</em>) and Moses do not go from the camp, marking the advance as self-initiated human action without divine authorization.</p>",
        "45": "<p>The result: <em>wayyakkem wayyakteʾû</em> — they struck them and shattered them. The Amalekites and Canaanites attack from their hill country position. <em>ʿad-haḥormâ</em> — as far as Hormah — a place name that may be a pun on <em>ḥerem</em> (devoted to destruction); this same location will become a site of Israelite victory in Num 21:3, showing that the geography of defeat can become the geography of victory when the generation changes and faith is restored.</p>"
    },
    "15": {
        "1": "<p>Chapter 15 opens with a new divine speech unit addressed to Moses after the sentence of ch14. The placement is theologically significant: immediately after pronouncing the wilderness-generation sentence, YHWH begins legislating for the land. The offering laws of ch15 presuppose entry into Canaan (<em>kî tāḇōʾû ʾel-ʾereṣ</em>), assuring the next generation that the promise remains in force even as the current generation is excluded.</p>",
        "2": "<p><em>ʾel-bənê yiśrāʾēl</em> — to the Israelites — the address covers all of Israel, not the doomed generation alone. The legislation is future-oriented: <em>ʾăšer ʾănî nōtēn lākem</em> — which I am giving you. The present participle marks the land promise as ongoing and certain despite the immediately preceding judgment. This structural juxtaposition is the canonical statement: judgment on one generation does not annul YHWH's covenant purpose.</p>",
        "3": "<p>The <strong>אִשֶּׁה (ʾiššeh)</strong> — food offering by fire — is the generic category covering burnt offerings, vow fulfillments, freewill offerings, and festival offerings. The phrase <em>ləʿăśôt rêaḥ nîḥôaḥ laYHWH</em> — to make a pleasing aroma to YHWH — uses the olfactory idiom that appears throughout Leviticus; it expresses acceptance, the offering achieving its intended purpose of divine reception.</p>",
        "4": "<p>The graduated grain and oil quantities create a proportional system: smaller animals require smaller accompaniments, larger animals require larger ones. <strong>עֲשִׂירִת הָאֵפָה (ʿăśîrît hāʾēpâ)</strong> — one-tenth of an ephah — approximately two liters of fine flour. <strong>הִין (hîn)</strong> is an Egyptian-derived liquid measure. The precision of these specifications serves cultic integrity: the offering must meet defined requirements, not be ad hoc.</p>",
        "5": "<p><strong>יַיִן (yayin)</strong> — wine — as drink offering. A quarter <em>hîn</em> accompanies lamb-size offerings. The drink offering (<em>nesek</em>) complements the grain offering and burnt offering, completing a meal-like presentation: bread (grain), oil (fat), and wine (drink). The tripartite offering structure reflects the full range of agricultural produce, offering back to YHWH the firstfruits of what the land will yield.</p>",
        "6": "<p>For a ram (larger animal), the quantities double: two-tenths of an ephah of flour and one-third of a hin of oil. The graduated scale distinguishes between categories of animals in terms of both their value and the proportional offering they require. The system ensures that larger offerings carry larger obligations, preventing the reduction of significant sacrifices to minimal accompaniments.</p>",
        "7": "<p>One-third of a hin of wine for the ram's drink offering. The repetition of <em>rêaḥ nîḥôaḥ laYHWH</em> — a pleasing aroma to YHWH — across the graduated offerings asserts that each tier achieves the same acceptance regardless of size; the smaller offering is equally valid.</p>",
        "8": "<p>The bull (<em>ben-bāqār</em>) — the largest common sacrifice — carries the highest requirements. The bull appears in peace/fellowship offerings, vow fulfillment, and burnt offerings. The specification covers all major sacrificial contexts for the largest animal category, ensuring the accompanying offerings scale appropriately.</p>",
        "9": "<p>Three-tenths of an ephah and half a hin of oil for the bull — the quantities have increased from the lamb's one-tenth/one-quarter to the bull's three-tenths/half hin. The graduated scale demonstrates a consistent proportional logic: the more valuable the sacrifice, the more substantial the grain-and-oil presentation that accompanies it.</p>",
        "10": "<p>Half a hin of wine accompanies the bull, completing the graduated scale. The phrase <em>ʾiššeh rêaḥ nîḥôaḥ laYHWH</em> — a food offering, a pleasing aroma to YHWH — closes each tier with identical acceptance language, affirming that the whole system — from the smallest lamb to the largest bull — falls within the same framework of divine reception.</p>",
        "11": "<p><em>kākâ yēʿāśeh lāšôr hāʾeḥāḏ ʾô lāʾayil hāʾeḥāḏ</em> — this shall be done for each bull or ram. The legal rubric extends the graduated system to all animals without exception. The formula language — <em>kākâ yēʿāśeh</em> (thus shall it be done) — appears throughout sacrificial law as a standardizing closure marking the universal application of what has been stipulated.</p>",
        "12": "<p>Whatever the number of animals, the same proportional system applies per animal. The principle is per-animal consistency: the total offering scales linearly with the number of animals, preventing either inflation or reduction of the required accompaniments based on quantity.</p>",
        "13": "<p>Every <em>ʾezrāḥ</em> — native-born/citizen — shall follow this procedure. The word <strong>אֶזְרָח (ʾezrāḥ)</strong> literally means one who sprouts or rises from the soil, suggesting indigenous rootedness. It stands in contrast to <em>gēr</em> (resident alien), which the following verses include equally. The primary audience is the settled Israelite community, but the law's inclusivity in vv14-16 extends beyond it.</p>",
        "14": "<p>The resident alien (<strong>גֵּר, gēr</strong>) — a sojourner without full tribal citizenship who lives under Israel's protection — is included under the same law. The inclusion of the <em>gēr</em> in the sacrificial system is characteristic of P legislation and reflects the covenant community's openness to non-ethnic members who live within its framework. <em>bəkol-dōrōtêkem</em> — throughout your generations — makes the inclusion permanent.</p>",
        "15": "<p><em>ḥuqqâ ʾaḥat</em> — one statute — governing both native and alien. The word <strong>חֻקָּה (ḥuqqâ)</strong> — statute/ordinance — marks this as binding law rather than custom. The inclusion clause <em>kāgēr kāʾezrāḥ yihyeh</em> — as the resident alien so the native — formally equalizes the legal status of both categories before YHWH. The social distinction remains; the cultic standing is identical.</p>",
        "16": "<p><em>tôrâ ʾaḥat ûmišpāṭ ʾeḥāḏ yihyeh lākem</em> — one law and one ordinance for you. <strong>תּוֹרָה (tôrâ)</strong> (instruction/law) and <strong>מִשְׁפָּט (mišpāṭ)</strong> (judgment/ordinance) together form a comprehensive legal pair. The verse is remarkable in the ancient Near Eastern context: most legal systems maintained strict distinctions between citizens and resident aliens. Israel's sacrificial law intentionally equalizes them, anticipating the universalism more fully developed in the prophets (Isa 56:6-7).</p>",
        "17": "<p>A new divine speech unit legislating the <strong>תְּרוּמָה (tərûmâ)</strong> — contribution/heave offering — of the first dough. The repeated speech formula (<em>waydabber YHWH ʾel-Moshe lēmôr</em>) signals a new discrete legal unit, not a continuation of the offering quantities. The laws of vv17-21 address a different aspect of the offering system: the gift from the first-processed grain of the harvest.</p>",
        "18": "<p><em>bəḇōʾăkem ʾel-hāʾāreṣ ʾăšer ʾănî mēḇîʾ ʾetkem šāmmâ</em> — when you come into the land to which I am bringing you. The syntax emphasizes YHWH as the active bringer (<em>mēḇîʾ</em>); Israel's entry is not their own achievement but divine leading. This framing continues the land-promise assurance that follows the judgment of ch14 — the land remains the destination YHWH is leading to.</p>",
        "19": "<p>When eating from the land's produce (<em>ûmilleḥem hāʾāreṣ tōʾkelû</em>), Israel shall present a contribution (<em>tərûmâ</em>) to YHWH. The gift from the agricultural yield frames every harvest meal as an act of acknowledgment: what grows from the land belongs to YHWH. The offering transforms ordinary eating into covenantal reception of divine gift.</p>",
        "20": "<p>The specific offering is a loaf of <em>ʿărîsôt</em> — the first of the dough, from the threshing-floor gift (<em>kirûmat gōren</em>). <strong>עָרִיסָה (ʿărîsâ)</strong> appears to mean a lump of dough; the offering is made before baking commences, giving YHWH the first processed grain. The comparison <em>kəterûmat gōren</em> — as the contribution from the threshing floor — connects bread-making to harvest offering as parallel first-fruits gestures.</p>",
        "21": "<p><em>mērēʾšît ʿărîsōtêkem tittənû laYHWH tərûmâ</em> — from the first of your dough you shall give a contribution to YHWH. The phrase <em>lədōrōtêkem</em> — throughout your generations — frames the law as permanent agricultural practice, not one-time inaugural offering. The first-of-dough gift becomes a recurring covenant act embedded in the routine of Israelite domestic life, connecting kitchen and sanctuary.</p>",
        "22": "<p>The <em>šegāgâ</em> legislation begins (vv22-29): laws governing unintentional sin by the community. <strong>שְׁגָגָה (šəgāgâ)</strong> — inadvertent error, stumbling/wandering from the right path — is distinguished from intentional transgression throughout Leviticus (4:2, 13; 5:18) and Numbers. The root <em>šāgag</em> means to go astray, to err. The legal distinction between inadvertent and deliberate sin is fundamental to the atonement system.</p>",
        "23": "<p>The scope: all commandments YHWH commanded through Moses, from the day of the commandment onwards throughout generations. The formula emphasizes the continuous applicability of the Mosaic legislation: there is no statute of limitations on covenantal obligation. The phrase <em>ûlahāʾlāh lədōrōtêkem</em> — and onward throughout your generations — frames the law as perpetually binding.</p>",
        "24": "<p>Community unintentional sin (<em>min-hāʿēḏâ bišgāgâ</em>) requires a whole burnt offering bull plus a sin offering male goat plus accompanying grain and drink offerings. The communal sin offering is more elaborate than the individual one (v27), reflecting the greater weight of communal culpability. The assembly (<em>kol-hāʿēḏâ</em>) must offer as a body; the sin is not distributable to individuals when it is a corporate failure of understanding.</p>",
        "25": "<p><em>wəkippar hakkōhēn ʿal-kol-ʿăḏat bənê yiśrāʾēl wənislaḥ lāhem</em> — the priest shall make atonement for the whole congregation and they shall be forgiven. The atonement/forgiveness sequence here uses the passive <em>nislāḥ</em> — it was forgiven — with YHWH as implied agent, parallel to the sālaḥ of 14:20. Atonement is priestly work; forgiveness is divine action. The two are sequential and inseparable in the Levitical system.</p>",
        "26": "<p>The inclusivity of community forgiveness: the whole congregation plus the resident alien (<em>wegam-laggēr</em>) dwelling among them are forgiven, since the whole people was involved in the inadvertent sin. The legal inclusion of the <em>gēr</em> in community atonement parallels the inclusion in community offering (vv14-16). The covenant community's ritual acts cover those who have joined themselves to it, regardless of ethnic origin.</p>",
        "27": "<p>Individual unintentional sin requires a yearling female goat (<em>ʿēz bat-šənātāh</em>) as a sin offering. The diminished scale — one animal versus the communal bull-plus-goat — reflects individual versus corporate accountability. The sin offering for an individual corresponds to the lowest-cost sacrifice for the most common kind of inadvertent transgression, ensuring access for all economic strata.</p>",
        "28": "<p>The priest makes atonement for the individual who sinned unintentionally before YHWH, and forgiveness follows. The legal sequence — sin → offering → priestly atonement → divine forgiveness — is identical for individual and community. The consistency of the structure across different sin-scales establishes the universality of the atonement mechanism: the same theological logic applies regardless of the scope of the failure.</p>",
        "29": "<p><em>tôrâ ʾaḥat yihyeh lākem</em> — one law for you — again the equalizing formula (cf. v16). Both native-born and resident alien come under the same inadvertent-sin law. The legal universality of the system is reinforced: one offering structure, one atonement process, one forgiveness outcome, for all within the covenant community regardless of origin.</p>",
        "30": "<p>The deliberate sinner: <em>wəhannep̱eš ʾăšer-taʿăśeh bəyāḏ rāmâ</em> — the person who acts with a high hand. <strong>בְּיָד רָמָה (bəyāḏ rāmâ)</strong> — with a raised/high hand — is the idiom for bold, presumptuous, defiant action; the same phrase describes Israel leaving Egypt (Exod 14:8; Num 33:3) with triumphant confidence. Here it describes deliberate defiance of YHWH. Such a person <em>ʾet-YHWH hûʾ megaddēp̱</em> — blasphemes YHWH — using the Piel of <strong>גָּדַף (gāḏap̱)</strong>, to revile/insult. No atoning sacrifice exists for this category of sin.</p>",
        "31": "<p>The deliberate blasphemer has despised the word of YHWH (<em>deḇar-YHWH bāzâ</em>) and broken his commandment (<em>miṣwātô hēp̱ar</em>). The sentence: <em>hikkārēt tikkārēt hann ep̱eš hahîʾ</em> — that person shall utterly be cut off — using the <em>kārēt</em> penalty (death/excommunication) that appears throughout the Torah for the most serious offenses. The repetition (<em>hikkārēt tikkārēt</em>) — the cognate infinitive absolute — intensifies the certainty and completeness of the cutting off. Her iniquity is upon her (<em>ʿăwōnāh bāh</em>) — she bears it herself with no priestly transfer.</p>",
        "32": "<p>The case of the Sabbath-wood-gatherer (vv32-36) provides a concrete application of the high-handed sin principle. A man found gathering wood on the Sabbath day (<em>bəyôm haššabbāt</em>) is the canonical test case. Wood-gathering involves intentional, visible labor; the prohibition on Sabbath work was established (Exod 20:8-11; 31:14-15). This is not inadvertent error but deliberate action in a clearly prohibited category.</p>",
        "33": "<p>The man is brought before Moses, Aaron, and the whole congregation — the full judicial structure of the covenant community. The legal process is public and communal, not private or informal. The presentation to all three — prophet, priest, and community — reflects the three-fold accountability structure of Israelite governance.</p>",
        "34": "<p><em>wayannîḥû ʾōtô bammišmār</em> — they put him in custody. The reason: <em>lōʾ p̱ōraš mah-yēʿāśeh lô</em> — it had not been made clear what should be done to him. This is one of the rare cases where the Torah explicitly acknowledges a gap in the existing legislation at the time it was being established. The custody pending divine clarification shows the process by which case law expanded the Mosaic corpus (cf. Num 9:8; 27:5).</p>",
        "35": "<p>YHWH's direct answer: <em>môt yûmat hāʾîš</em> — the man shall be put to death. The double verb form (<em>môt yûmat</em> — die he shall die) is the standard Torah formula for capital offenses. The prescribed method: stoning by the whole congregation outside the camp. The communal execution — not by authority figures but by all the assembly — involves the community itself in the enforcement of covenant law.</p>",
        "36": "<p>The execution is carried out exactly as commanded: <em>kəʾăšer ṣiwwâ YHWH ʾet-Moshe</em> — as YHWH commanded Moses. The act of execution is thus not mob violence but covenantal obedience. The case serves as a legal precedent establishing that the high-handed sin principle (v30-31) applies to Sabbath violation, and that the penalty is capital. The placement immediately after the šegāgâ/bəyāḏ rāmâ distinction makes the narrative case for the legislative principle.</p>",
        "37": "<p>A final new speech unit (vv37-41): the tassel law. The address formula again marks this as a discrete legal unit. The tassel law follows the sin-distinction laws, providing a positive mnemonic device as the practical solution to the problem the chapter has been addressing: how does Israel avoid falling into inadvertent or deliberate sin? By having constant visual reminders of the commandments.</p>",
        "38": "<p><em>ṣîṣit ʿal-kanp̱ê bigdêhem</em> — tassels on the corners of their garments. <strong>צִיצִת (ṣîṣit)</strong> — tassel/fringe — appears only here and in Num 15 and Deut 22:12. A thread of <strong>תְּכֵלֶת (tékelet)</strong> — blue/violet dye — is to be woven into the tassel. <em>Tékelet</em> is the expensive marine-derived blue used in the tabernacle curtains (Exod 26:1) and high priestly garments (Exod 28:5,6). Including this color threads ordinary clothing into the symbolic world of the sanctuary.</p>",
        "39": "<p><em>ûrəʾîtem ʾōtô ûzəkartem ʾet-kol-miṣwōt YHWH</em> — you shall look at them and remember all the commandments of YHWH. The tassel is a visual mnemonic (<em>zikārôn</em>-function): seeing triggers remembering. The chain of visual reminder → memory → action prevents the drift toward personal desire (<em>ʾaḥărê lěbaḇkem</em>) and eyes (<em>ʾaḥărê ʿênêkem</em>) that leads to spiritual infidelity. The phrase <em>zōnîm ʾaḥărêhem</em> — playing the harlot after them — uses the sexual-unfaithfulness metaphor for covenant violation.</p>",
        "40": "<p><em>lemaʿan tizkorû waʿăśîtem ʾet-kol-miṣwōtāy</em> — so that you may remember and do all my commandments. The purpose of the tassels is behavioral: not meditation but obedience. <em>wihyîtem qəḏōšîm lēʾlōhêkem</em> — you shall be holy to your God. The holiness formula (<em>qədôšîm</em>) connects to the Levitical holiness code (Lev 19-20) and frames practical mnemonic technology within the theological category of covenant consecration.</p>",
        "41": "<p><em>ʾănî YHWH ʾĕlōhêkem ʾăšer hôṣêtî ʾetkem mēʾereṣ miṣrāyim lihyôt lākem lēʾlōhîm</em> — I am YHWH your God who brought you out of the land of Egypt to be your God. The <em>ʾănî YHWH</em> formula — I am YHWH — appears throughout Leviticus as the grounding of covenantal obligation. The exodus event is cited as the constitutive act: being God to Israel is defined by the act of liberation. The chapter closes by returning to the foundational covenant relationship after its long legislative development.</p>"
    }
}

def main():
    data = load_comm('mkt-original', 'numbers')
    merge_comm(data, NUMBERS)
    save_comm('mkt-original', 'numbers', data)

main()
